INSERT INTO public.agents VALUES ('f17e51ca-4c4c-47bb-8c4b-84516ab5505c', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Engineering Manager', 'pm', 'Engineering Project Manager', 'idle', '635f3a34-c54a-4b59-ab25-e73fc30b6cf3', 'Receives engineering tasks, project requests, and technical problems. Breaks down work into actionable subtasks. Delegates to Frontend UI Engineer and Backend Engineer. Manages sprint priorities and unblocks the engineering team. Reviews technical proposals and ensures quality delivery.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/f17e51ca-4c4c-47bb-8c4b-84516ab5505c/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/f17e51ca-4c4c-47bb-8c4b-84516ab5505c/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:16:45.456+00', NULL, '2026-03-30 13:05:29.081527+00', '2026-03-31 15:16:45.456+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": true}', 'wrench', NULL, NULL);
INSERT INTO public.agents VALUES ('161f306b-7c88-4de6-9918-b1a3b02246ce', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Research Specialist', 'general', 'Research Specialist & R&D Analyst', 'idle', '635f3a34-c54a-4b59-ab25-e73fc30b6cf3', 'Web research and competitive intelligence gathering. Technology evaluation and comparison analysis. Screen scraping and profile analysis for market research. Business process and workflow improvement research. Trend analysis and emerging technology assessment. Produces structured research reports with actionable recommendations.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/161f306b-7c88-4de6-9918-b1a3b02246ce/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/161f306b-7c88-4de6-9918-b1a3b02246ce/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:16:45.949+00', NULL, '2026-03-30 11:19:22.392067+00', '2026-03-31 15:16:45.949+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'telescope', NULL, NULL);
INSERT INTO public.agents VALUES ('3071507e-da74-46bd-b521-cf16eb00f9b4', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Frontend Engineer', 'engineer', 'Frontend UI Engineer', 'idle', 'f17e51ca-4c4c-47bb-8c4b-84516ab5505c', 'Builds and maintains frontend user interfaces using JavaScript, TypeScript, CSS, and modern frameworks (React, Vue, Next.js, Tailwind). Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Backend Engineers before implementing features that require API integration or backend cooperation. Produces accessible, responsive, and performant UI components.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/3071507e-da74-46bd-b521-cf16eb00f9b4/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/3071507e-da74-46bd-b521-cf16eb00f9b4/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:16:45.225+00', NULL, '2026-03-30 13:14:34.571205+00', '2026-03-31 15:16:45.225+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'code', NULL, NULL);
INSERT INTO public.agents VALUES ('029b2109-796f-4970-a727-88424580c1d9', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Marie', 'general', 'Executive Assistant to the CEO', 'idle', '635f3a34-c54a-4b59-ab25-e73fc30b6cf3', 'Tracks and follows up on delegated work across all teams. Prepares status summaries and progress reports. Manages task prioritization and scheduling. Coordinates cross-functional communication. Executes routine operational tasks on behalf of the CEO. Surfaces blockers and escalates proactively. Maintains organizational context and institutional memory.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/029b2109-796f-4970-a727-88424580c1d9/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/029b2109-796f-4970-a727-88424580c1d9/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:16:50.146+00', NULL, '2026-03-30 10:24:58.762446+00', '2026-03-31 15:16:50.146+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'star', NULL, NULL);
INSERT INTO public.agents VALUES ('25b0ef20-c35a-4db2-a8cd-841d46dfedcd', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Paralegal', 'general', 'Paralegal & Legal Operations Specialist', 'idle', '1a865d2d-3b6d-4ac6-b3c4-4ccfbb9c8a30', 'Performs all legal legwork including due diligence, legal research, document processing, compliance data gathering, and cross-agent coordination. Works with the Research Specialist for data sourcing and the Executive Assistant for CEO communications. Prepares all work product for General Counsel review. Does not issue legal opinions or make compliance determinations.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/25b0ef20-c35a-4db2-a8cd-841d46dfedcd/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/25b0ef20-c35a-4db2-a8cd-841d46dfedcd/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:25:45.804+00', NULL, '2026-03-31 08:59:04.608885+00', '2026-03-31 15:25:45.804+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'shield', NULL, NULL);
INSERT INTO public.agents VALUES ('beb6459f-8b56-4270-a1e8-6043dd575548', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'Backend Engineer', 'engineer', 'Backend Engineer', 'idle', 'f17e51ca-4c4c-47bb-8c4b-84516ab5505c', 'Builds and maintains server-side applications, APIs, database schemas, business logic, integrations, infrastructure, and backend performance. Uses Node.js, Python, SQL, and modern backend frameworks. Follows test-driven development (TDD) patterns — writes tests first, then implements. Always verifies changes pass tests and linting before committing. Communicates with Engineering Manager for task clarification and progress updates. Coordinates with Frontend Engineers on API contracts and integration points. Produces reliable, secure, and performant backend services.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/beb6459f-8b56-4270-a1e8-6043dd575548/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/beb6459f-8b56-4270-a1e8-6043dd575548/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:16:48.183+00', NULL, '2026-03-30 13:51:58.18245+00', '2026-03-31 15:16:48.183+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'database', NULL, NULL);
INSERT INTO public.agents VALUES ('1a865d2d-3b6d-4ac6-b3c4-4ccfbb9c8a30', 'd614ecc3-b46c-47cc-af90-7d2b33e0a47e', 'General Counsel', 'general', 'General Counsel & Chief Legal Officer', 'idle', '635f3a34-c54a-4b59-ab25-e73fc30b6cf3', 'Handles all legal procedures, proceedings, and matters. Composes, edits, evaluates, and reviews legal documents including contracts, agreements, policies, and compliance frameworks. Monitors regulatory compliance and enforces legal standards across the organization. Protects intellectual property and proprietary information. Evaluates and improves legal structure and corporate governance. Has authority to halt any activity deemed illegal or non-compliant until the CEO reviews and provides clearance. Maintains strict confidentiality — does not disclose work product or legal matters to other agents. Reports exclusively to the CEO.', 'claude_local', '{"graceSec": 15, "timeoutSec": 0, "maxTurnsPerRun": 200, "instructionsFilePath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/1a865d2d-3b6d-4ac6-b3c4-4ccfbb9c8a30/instructions/AGENTS.md", "instructionsRootPath": "/paperclip/instances/default/companies/d614ecc3-b46c-47cc-af90-7d2b33e0a47e/agents/1a865d2d-3b6d-4ac6-b3c4-4ccfbb9c8a30/instructions", "instructionsEntryFile": "AGENTS.md", "instructionsBundleMode": "managed", "dangerouslySkipPermissions": true}', 0, 0, '2026-03-31 15:27:43.684+00', NULL, '2026-03-31 08:27:51.727867+00', '2026-03-31 15:27:43.684+00', '{"heartbeat": {"enabled": true, "intervalSec": 1800, "wakeOnDemand": true, "maxConcurrentRuns": 1}}', '{"canCreateAgents": false}', 'shield', NULL, NULL);


